const conversationSummary = Context.getVariable("conversationSummary");
const customerPhoneNumber = Context.getVariable("customerPhoneNumber");
const customerEmailAddress = Context.getVariable("customerEmailAddress");
const customerOrderNumber = Context.getVariable("customerOrderNumber");

const escalation_data = `Customer Information:
${customerPhoneNumber || 'N/A'}
${customerEmailAddress || 'N/A'}
${customerOrderNumber || 'N/A'}

Conversation Summary:
${conversationSummary || 'N/A'}`;

Context.setVariable("escalation_data", escalation_data);

function normalizeID(id) {
    if (!id || typeof id !== 'string') {
        Context.setVariable("workflow_status", "phone number is not valid")
        return '';
    }

    // Remove all non-digit characters: spaces, hyphens, parentheses, dots, etc.
    // Examples: "(123) 456-7890" → "1234567890", "ORD-12345" → "12345"
    return id.replace(/\D/g, '');
}

const customerPhoneNumber = Context.getVariable("customerPhoneNumber")
const customerOrderNumber = Context.getVariable("customerOrderNumber")
const normalizedPhoneNumber = normalizeID(customerPhoneNumber)
const normalizedOrderNumber = normalizeID(customerOrderNumber)
Context.setVariable("customerPhoneNumber", normalizedPhoneNumber)
Context.setVariable("customerOrderNumber",normalizedOrderNumber)

const ordersList = [
  {
    "orderId": 7538515,
    "salesChannel": "Canada : Webstore",
    "dateOrdered": "2026-01-19T21:41:54+00:00",
    "packageCount": 2,
    "trackingInfo": [
      {
        "shipperName": "GLS Canada Parcel",
        "trackingNumber": "P2579583601"
      },
      {
        "shipperName": "GLS Canada Parcel",
        "trackingNumber": "P2579583602"
      }
    ]
  },
  {
    "orderId": 7531225,
    "salesChannel": "Canada : Customer Service Representative",
    "dateOrdered": "2026-01-14T09:21:19+00:00",
    "packageCount": 3,
    "trackingInfo": [
      {
        "shipperName": "UPS Canada Ground",
        "trackingNumber": "1Z0A89R22099781157"
      },
      {
        "shipperName": "UPS Canada Ground",
        "trackingNumber": "1Z0A89R22099699569"
      },
      {
        "shipperName": "UPS Canada Ground",
        "trackingNumber": "1Z0A89R22096291576"
      }
    ]
  }
]
Context.setVariable('workflow_status', '');
Context.setVariable('reason', '');
Context.setVariable('parsedOrdersInfo', ordersList);
Context.setVariable('orderCount', 2);

// Parse order API response and extract key information for Agent use
function parseOrdersData(ordersList) {

  // Build order summaries (sorted by order date descending, newest first)
  const orderSummaries = ordersList
    .map((order) => {
      const packages = order.shipments?.packages || [];
      const packageCount = packages.length;

      // Extract tracking info (keep only shipperName and trackingNumber)
      const trackingInfo = packages.map(pkg => ({
        shipperName: pkg.shipperName,
        trackingNumber: pkg.trackingNumber
      }));

      return {
        orderId: order.salesOrderId,
        salesChannel: order.salesChannel,
        dateOrdered: order.dateOrdered,
        packageCount,
        trackingInfo
      };
    })
    .sort((a, b) => new Date(b.dateOrdered).getTime() - new Date(a.dateOrdered).getTime()); // Sort by time descending

  return orderSummaries;
}

const ordersList = Context.getVariable('ordersList');
const parsedData = parseOrdersData(ordersList);

Context.setVariable('workflow_status', "success");
Context.setVariable('parsedOrdersInfo', parsedData);

function validateAndFormatNANP(phone) {
    // Step 1: Check for null/undefined/empty
    if (!phone && phone !== 0) {
      Context.setVariable("workflow_status", "failure");
      Context.setVariable("reason", "No phone number provided");
      return false;
    }

    // Step 2: Convert to string and clean up
    let s = String(phone).trim();

    // Step 3: Remove extension markers (ext, x, #, etc.)
    // e.g. "123-456-7890 ext 12" -> "123-456-7890"
    s = s.replace(/\s*(?:ext|x|#|ext\.)\s*\d+$/i, "");

    // Step 4: Extract only digits
    const digits = s.replace(/\D+/g, "");

    // Step 5: Validate and format (US/Canada both use +1 country code)
    if (digits.length === 11 && digits.startsWith("1")) {
      // Country code format: +1xxxxxxxxxx (11 digits, starts with 1)
      Context.setVariable("workflow_status", "success");
      return `+${digits}`;
    } else if (digits.length === 10) {
      // National format: xxxxxxxxxx (10 digits, no country code)
      Context.setVariable("workflow_status", "success");
      return `+1${digits}`;
    } else {
      // Invalid format
      Context.setVariable("workflow_status", "failure");

      // Distinguish between likely international and format error
      if (digits.length > 11 || (digits.length > 10 && !digits.startsWith("1"))) {
        Context.setVariable("reason", "International phone number not supported");
      } else {
        Context.setVariable("reason", "Phone number does not match US/Canada formats");
      }

      return false;
    }
}

Context.setVariable("workflow_status", "")
const phone_number = Context.getVariable("smsPhoneNumber")
const validateResult = validateAndFormatNANP(phone_number)

if (!validateResult) {
    Context.setVariable("phone_number_acceptable", "No")
} else {
    Context.setVariable("phone_number_acceptable", "Yes")
    Context.setVariable("smsPhoneNumber", validateResult)
}

/**
 * Build tracking URL based on shipper name and tracking numbers
 * @param {string} shipperName - Name of the shipping carrier
 * @param {string[]} trackingNumbers - Array of tracking numbers
 * @returns {string|false} - Constructed tracking URL or false if unsupported
 */
function buildTrackingURL(shipperName, trackingNumbers) {

  // Normalize shipper name (lowercase, trim whitespace)
  const normalized = shipperName.trim().toLowerCase();

  // Keyword-based matching - identifies shipper type regardless of full name variation
  if (normalized.includes('ups')) {
    const params = trackingNumbers.map((n, i) => `InquiryNumber${i + 1}=${n}`).join('&');
    return `https://www.ups.com/track?TypeOfInquiryNumber=T&${params}`;
  }

  if (normalized.includes('fedex')) {
    return `https://www.fedex.com/fedextrack/summary?trknbr=${trackingNumbers.join(',')}`;
  }

  if (normalized.includes('canpar')) {
    return `https://www.canpar.com/en/tracking/track.htm?barcode=${trackingNumbers.join(',')}`;
  }

  if (normalized.includes('gls')) {
    return `https://www.gls-canada.com/track?tracking=${trackingNumbers.join(',')}`;
  }

  // Unsupported shipper
  return false;
}


// Main execution
Context.setVariable("workflow_status", "")

const parsedOrdersInfo = Context.getVariable("parsedOrdersInfo");

if (!parsedOrdersInfo || parsedOrdersInfo.length === 0) {
  Context.setVariable("workflow_status", "failure");
  Context.setVariable("reason", "No order information found");
} else {
  // Get the first order
  const order = parsedOrdersInfo[0];
  const trackingInfo = order.trackingInfo;

  if (!trackingInfo || trackingInfo.length === 0) {
    Context.setVariable("workflow_status", "failure");
    Context.setVariable("reason", "No tracking information found for the order");
  } else {
    // Extract shipper name from first element (all elements have same shipper for one order)
    const shipperName = trackingInfo[0].shipperName;

    // Extract all tracking numbers into array
    const trackingNumbers = trackingInfo.map(info => info.trackingNumber);

    // Build tracking URL
    const trackingURL = buildTrackingURL(shipperName, trackingNumbers);

    if (!trackingURL) {
      Context.setVariable("workflow_status", "failure");
      Context.setVariable("reason", `Unsupported shipper: ${shipperName}`);
    } else {
      // Generate SMS message
      const smsMessage = `AutoShack: Thanks for contacting AutoShack customer support.
You can check the shipping status of your order using the link below:
${trackingURL}
If you have any other questions, feel free to contact us again.`;

      // Store results in Context
      Context.setVariable("workflow_status", "success");
      Context.setVariable("shipperName", shipperName);
      Context.setVariable("trackingNumbers", trackingNumbers);
      Context.setVariable("trackingURL", trackingURL);
      Context.setVariable("smsMessage", smsMessage);
    }
  }
}

const lang = Context.getVariable("language");
if (lang == "en-US") { Context.setVariable("km_segment", "external_us_eng"); }
else if (lang == "es-MX") { Context.setVariable("km_segment", "external_es"); }
else if (lang == "fr-CA") { Context.setVariable("km_segment", "external_fr"); }
